I'm upgrading my Android MatrixScan app from Scandit SDK v6 to v7. The app uses BarcodeTracking. Here is my Activity that I need migrated to the new API. Show me the full updated file.

```kotlin
package com.example.myapp

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import com.scandit.datacapture.barcode.tracking.capture.BarcodeTracking
import com.scandit.datacapture.barcode.tracking.capture.BarcodeTrackingListener
import com.scandit.datacapture.barcode.tracking.capture.BarcodeTrackingSession
import com.scandit.datacapture.barcode.tracking.capture.BarcodeTrackingSettings
import com.scandit.datacapture.barcode.tracking.data.TrackedBarcode
import com.scandit.datacapture.barcode.tracking.ui.overlay.BarcodeTrackingBasicOverlay
import com.scandit.datacapture.barcode.data.Symbology
import com.scandit.datacapture.core.capture.DataCaptureContext
import com.scandit.datacapture.core.data.FrameData
import com.scandit.datacapture.core.source.Camera
import com.scandit.datacapture.core.source.FrameSourceState
import com.scandit.datacapture.core.ui.DataCaptureView

class MainActivity : AppCompatActivity(), BarcodeTrackingListener {

    private val dataCaptureContext =
        DataCaptureContext.forLicenseKey("-- ENTER YOUR SCANDIT LICENSE KEY HERE --")
    private val camera = Camera.getDefaultCamera(BarcodeTracking.createRecommendedCameraSettings())
    private val barcodeTracking: BarcodeTracking

    init {
        dataCaptureContext.setFrameSource(camera)
        val settings = BarcodeTrackingSettings().apply {
            enableSymbology(Symbology.EAN13_UPCA, true)
        }
        barcodeTracking = BarcodeTracking.forDataCaptureContext(dataCaptureContext, settings)
        barcodeTracking.addListener(this)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        val view = DataCaptureView.newInstance(this, dataCaptureContext)
        BarcodeTrackingBasicOverlay.newInstance(barcodeTracking, view)
        setContentView(view)
    }

    override fun onSessionUpdated(mode: BarcodeTracking, session: BarcodeTrackingSession, data: FrameData) {}
    override fun onObservationStarted(barcodeTracking: BarcodeTracking) {}
    override fun onObservationStopped(barcodeTracking: BarcodeTracking) {}
}
